Here's how to test `DataFetcher` with proper timeout and cancellation handling:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act — pass CancellationToken so [Timeout] can cancel cooperatively
        var result = await fetcher.FetchAsync("http://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.NotFound);
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("http://example.com/missing",
                                                  _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — a handler that delays so cancellation fires first
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler("slow", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Cancel immediately
        cts.Cancel();

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("http://example.com", cts.Token));
    }

    // Minimal fake handler — avoids real HTTP calls
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public FakeHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content),
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly` field, satisfies nullability |
| `[Timeout(5000)]` + `_testContext.CancellationToken` | Cooperative timeout — test is actually cancelled, not just abandoned |
| `Assert.ThrowsExactlyAsync<T>` | Modern replacement for `[ExpectedException]`; lets you inspect the exception |
| `sealed` test class + `sealed` handler | Performance and design clarity |
| `FakeHandler` instead of real HTTP | Deterministic tests; the delay variant lets you verify cancellation without waiting |

The critical detail: **always pass `_testContext.CancellationToken`** to async calls in tests that have `[Timeout]`. Without it, the timeout attribute has no way to stop a hung operation cooperatively.
